/**
 * Debug: why do 120 candidates produce 0 patches?
 */
import { analyzePolyglotSource } from './polyglot-bridge';
import { readFileSync } from 'fs';

const r = await analyzePolyglotSource('src/checkpoint-substrates.ts');
const f = r.functions.find(fn => fn.functionName === 'diagnose');
if (!f) { console.log('diagnose not found'); process.exit(1); }

const nodes = f.bettyResult.ast?.nodes;
console.log('All node labels:');
if (nodes) {
  const labelCounts: Record<string, number> = {};
  for (const [id, node] of nodes) {
    for (const label of node.labels) {
      labelCounts[label] = (labelCounts[label] ?? 0) + 1;
    }
    // Show Entry-like nodes
    if (node.properties.source_line && node.properties.name) {
      console.log(`  ${id}: labels=${node.labels.join(',')} name=${node.properties.name} line=${node.properties.source_line}`);
    }
  }
  console.log('Label counts:', labelCounts);
}

// The polyglot scanner also puts the source span directly on the function result
// Check if the sourceMap has the entry info
console.log('\nSource map entries:', f.sourceMap.size);
for (const [nodeId, span] of f.sourceMap) {
  if (nodeId.includes('entry')) {
    console.log(`  ${nodeId}: line ${span.start_line}-${span.end_line}`);
  }
}

// The GG source has entry_0 with source_line in the properties
// But Betty parses it — does Betty preserve the Entry label?
console.log('\nGG source first line:', f.ggSource.split('\n').find(l => l.includes('Entry'))?.slice(0, 100));
